<?php if ( ! defined( 'ABSPATH' ) ) exit; $rules=qm2026_get_setting('default_rules',qm2026_default_rules()); ?>
<div class="wrap qm2026"><h1><?php esc_html_e('Ajustes y reglas de puntaje',QM2026_TEXT_DOMAIN); ?></h1><?php if(!empty($_GET['qm2026_notice'])) echo '<div class="notice notice-success"><p>'.esc_html(wp_unslash($_GET['qm2026_notice'])).'</p></div>'; ?><form method="post" class="qm2026-card"><?php wp_nonce_field('qm2026_admin_action'); ?><input type="hidden" name="qm2026_action" value="save_settings"><div class="qm2026-grid"><?php foreach(qm2026_default_rules() as $key=>$default): ?><label><?php echo esc_html($key); ?><input type="number" min="0" name="rules[<?php echo esc_attr($key); ?>]" value="<?php echo esc_attr($rules[$key]??$default); ?>"></label><?php endforeach; ?></div><p><label><input type="checkbox" name="delete_on_uninstall" value="1" <?php checked(qm2026_get_setting('delete_on_uninstall','0'),'1'); ?>> <?php esc_html_e('Borrar datos al desinstalar',QM2026_TEXT_DOMAIN); ?></label></p><p><button class="button button-primary"><?php esc_html_e('Guardar ajustes',QM2026_TEXT_DOMAIN); ?></button></p></form></div>
